import{_ as e,o,c as d,a0 as s}from"./chunks/framework.C6nzqSM0.js";const u=JSON.parse('{"title":"权限开通说明","description":"","frontmatter":{},"headers":[],"relativePath":"zh/reference/permissions.md","filePath":"zh/reference/permissions.md","lastUpdated":1781385680000}'),a={name:"zh/reference/permissions.md"};function i(c,t,n,r,l,h){return o(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="权限开通说明" tabindex="-1">权限开通说明 <a class="header-anchor" href="#权限开通说明" aria-label="Permalink to &quot;权限开通说明&quot;">​</a></h1><blockquote><p><strong>每个飞书/Lark bot 在能收消息、发回复、跟飞书文档交互之前,都必须在 app 后台开通 scopes</strong>。本页是哪些能力对应哪些 scopes 的清单,以及 怎么在 3 个 OS 上验证已开通。</p></blockquote><h2 id="按能力的-scope-清单" tabindex="-1">按能力的 scope 清单 <a class="header-anchor" href="#按能力的-scope-清单" aria-label="Permalink to &quot;按能力的 scope 清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>必须 scope (中文)</th><th>必须 scope (英文)</th><th>用途</th></tr></thead><tbody><tr><td><strong>接收私聊</strong></td><td><code>im:message</code></td><td><code>im:message</code></td><td>订阅 <code>im.message.receive_v1</code> 事件</td></tr><tr><td><strong>接收群 @bot</strong></td><td><code>im:message.group_at_msg</code> (或 <code>im:message</code> 收全部群消息)</td><td><code>im:message.group_at_msg</code></td><td>仅 @bot 或全部(per app 配置)</td></tr><tr><td><strong>发送私聊 / 群消息</strong></td><td><code>im:message.send_as_bot</code></td><td><code>im:message.send_as_bot</code></td><td>POST <code>/im/v1/messages</code></td></tr><tr><td><strong>读 user open_id</strong></td><td><code>contact:user.id:readonly</code></td><td><code>contact:user.id:readonly</code></td><td><code>sender.sender_id.open_id</code> 查询</td></tr><tr><td><strong>上传 / 发送图片</strong></td><td><code>im:resource</code></td><td><code>im:resource</code></td><td>图片消息经 <code>/im/v1/images</code></td></tr><tr><td><strong>上传 / 发送文件</strong></td><td><code>im:resource</code></td><td><code>im:resource</code></td><td>文件消息经 <code>/im/v1/files</code></td></tr><tr><td><strong>读飞书文档</strong></td><td><code>docx:document:readonly</code></td><td><code>docx:document:readonly</code></td><td>通过 <code>/docx/v1/documents/:id/raw_content</code> 取内容</td></tr><tr><td><strong>编辑飞书文档</strong></td><td><code>docx:document</code></td><td><code>docx:document</code></td><td>通过 <code>/docx/v1/documents/:id/...</code> 编辑</td></tr><tr><td><strong>创建飞书文档</strong></td><td><code>docx:document:create</code></td><td><code>docx:document:create</code></td><td>POST <code>/docx/v1/documents</code></td></tr><tr><td><strong>搜索飞书知识库 / 文档</strong></td><td><code>wiki:wiki:readonly</code></td><td><code>wiki:wiki:readonly</code></td><td>通过 <code>/wiki/v1/spaces/.../nodes/search</code> 搜索</td></tr><tr><td><strong>读 user email (少见)</strong></td><td><code>contact:user.email:readonly</code></td><td><code>contact:user.email:readonly</code></td><td>仅当 bot 发送邮件通知时</td></tr></tbody></table><p><strong>Per 主人定义</strong>(hermes/larkbot 需要 <strong>3 大块</strong> 全能力):</p><ol><li><strong>私聊</strong></li><li><strong>群聊</strong></li><li><strong>飞书文档</strong></li></ol><p>→ 上述 3 大块对应的 scope 都要开。</p><h2 id="按-os-验证路径" tabindex="-1">按 OS 验证路径 <a class="header-anchor" href="#按-os-验证路径" aria-label="Permalink to &quot;按 OS 验证路径&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><ol><li>Safari 打开 <code>https://open.feishu.cn/app</code></li><li>点你的 app → &quot;权限管理&quot;</li><li>验证上述 3 大块的 scopes 已勾选</li><li>也点 &quot;事件订阅&quot;: <ul><li>加 &quot;接收消息 im.message.receive_v1&quot;</li><li>Verification Token / Encrypt Key — 复制下来,粘到 <code>credentials.json</code> (仅 Webhook 模式需要;WS 模式不需要)</li></ul></li><li>终端验证 bot 进程能读:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu/credentials.json</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  {&quot;app_id&quot;: &quot;cli_xxx&quot;, &quot;app_secret&quot;: &quot;yyy&quot;}</span></span></code></pre></div></li></ol><h3 id="windows-wsl2" tabindex="-1">Windows (WSL2) <a class="header-anchor" href="#windows-wsl2" aria-label="Permalink to &quot;Windows (WSL2)&quot;">​</a></h3><p>跟 macOS 相同,但在 WSL 内:</p><ol><li><code>wsl</code> 进 Ubuntu</li><li><code>xdg-open https://open.feishu.cn/app</code> (或复制 URL 到 Windows 浏览器)</li><li>跟 macOS 步骤 2-5</li></ol><h3 id="linux-无-gui" tabindex="-1">Linux (无 GUI) <a class="header-anchor" href="#linux-无-gui" aria-label="Permalink to &quot;Linux (无 GUI)&quot;">​</a></h3><ol><li>在另一台机打开 <code>https://open.feishu.cn/app</code></li><li>应用 scopes,复制 Encrypt Key / Verification Token</li><li>SSH / scp 凭据:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 Linux box:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu/credentials.json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;EOF&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">{&quot;app_id&quot;: &quot;cli_xxx&quot;, &quot;app_secret&quot;: &quot;yyy&quot;}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/feishu/credentials.json</span></span></code></pre></div></li></ol><h2 id="按部署模式的-token-存储" tabindex="-1">按部署模式的 token 存储 <a class="header-anchor" href="#按部署模式的-token-存储" aria-label="Permalink to &quot;按部署模式的 token 存储&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部署</th><th>Token 存储</th><th>静态加密?</th></tr></thead><tbody><tr><td>macOS (本仓库)</td><td><code>~/Library/Application Support/lark-cli/master.key.file</code> + <code>appsecret_cli_&lt;appid&gt;.enc</code></td><td>✅ lark-cli AES-256-GCM</td></tr><tr><td>macOS (备选)</td><td><code>~/.config/feishu/credentials.json</code> (明文)</td><td>❌ (chmod 600)</td></tr><tr><td>Windows</td><td><code>%APPDATA%\\lark-cli\\...</code> 或 <code>~/.config/feishu/credentials.json</code></td><td>取决</td></tr><tr><td>Linux</td><td><code>~/.config/feishu/credentials.json</code> (明文) 或 systemd credential store</td><td>❌ 或 ✓</td></tr></tbody></table><p><strong>推荐</strong>: 能用 lark-cli 加密就用(macOS 本仓库这样),明文 + <code>chmod 600</code> 是 fallback。</p><h2 id="权限被回收-症状" tabindex="-1">&quot;权限被回收&quot; 症状 <a class="header-anchor" href="#权限被回收-症状" aria-label="Permalink to &quot;&quot;权限被回收&quot; 症状&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>修</th></tr></thead><tbody><tr><td>ws 连上后 1-2 消息就死, log &quot;permission denied&quot;</td><td>飞书 admin 移除了一个 scope</td><td>后台重开;重启 bot daemon</td></tr><tr><td>Send API 返回 <code>99991663</code> (no scope)</td><td>代码调了未开的 scope</td><td>加 scope;等 1-2 分钟(飞书 cache)</td></tr><tr><td>Receive API 工作但 <code>sender</code> 字段空</td><td>缺 <code>contact:user.id:readonly</code></td><td>加 scope</td></tr><tr><td><code>reply</code> POST 返回 404 (chat not found)</td><td>Bot 不在该群</td><td>先 invite bot 进群</td></tr></tbody></table><h2 id="跨-os-后台改-1-处-自动传播" tabindex="-1">跨 OS: 后台改 1 处,自动传播 <a class="header-anchor" href="#跨-os-后台改-1-处-自动传播" aria-label="Permalink to &quot;跨 OS: 后台改 1 处,自动传播&quot;">​</a></h2><p>你在飞书后台重开 scope:</p><ul><li>1-2 分钟内传播到所有客户端(WS / Webhook)</li><li><strong>不需要</strong> 重启 bot daemon</li><li>但: 飞书 SDK 在连接时可能 cache scope 列表;bot 跑着时开 scope,可能需重连 (kill + restart)</li></ul><h2 id="相关" tabindex="-1">相关 <a class="header-anchor" href="#相关" aria-label="Permalink to &quot;相关&quot;">​</a></h2><ul><li><a href="./../guides/connection-modes">连接方式对比</a> — WS vs Webhook</li><li><a href="./../guides/ai-tools-hermes">Hermes 集成</a></li><li><a href="./../protocol/feishu-inbox-protocol">inbox/outbox 协议</a></li></ul>`,25)])])}const g=e(a,[["render",i]]);export{u as __pageData,g as default};
